import{_ as r}from"./chunks/DemoViewer.vue_vue_type_script_setup_true_lang.uKCvko_a.js";import{w as s,x as t,y as n,z as i}from"./chunks/theme.C49JthOR.js";import{u as o}from"./chunks/link-icons.BeUxiLwc.js";import{a3 as l,o as c,c as h,p as a,a as p,v,ah as d}from"./chunks/framework.cbxun9lb.js";import"./chunks/index.B5B05-aR.js";const S=JSON.parse('{"title":"JSON Canvas Viewer","titleTemplate":"在浏览器中渲染 JSON Canvas 的库套件","description":"JSON Canvas Viewer 是一个前端库，提供可扩展的 JSON Canvas 查看器，能够轻松集成到任何现有框架和范式中。","frontmatter":{"layout":"project","title":"JSON Canvas Viewer","titleTemplate":"在浏览器中渲染 JSON Canvas 的库套件","description":"JSON Canvas Viewer 是一个前端库，提供可扩展的 JSON Canvas 查看器，能够轻松集成到任何现有框架和范式中。","logo":"https://github.com/hesprs/json-canvas-viewer/raw/main/assets/logo.svg","links":[{"name":"GitHub 仓库","url":"https://github.com/hesprs/json-canvas-viewer","color":"#010409"},{"name":"npm","url":"https://www.npmjs.com/package/json-canvas-viewer","color":"#EA2039"},{"name":"文档","url":"https://github.com/hesprs/json-canvas-viewer/wiki","color":"#425aef"},{"name":"JSON Canvas","url":"https://jsoncanvas.org","color":"#8B0A5F"}],"head":[["meta",{"name":"keywords","content":"JSON Canvas, JSON Canvas Viewer, Obsidian, Obsidian Canvas, 可视化, React 组件, Vue 组件, Preact 组件, npm 库, JavaScript, TypeScript"}]]},"headers":[],"relativePath":"zh-Hans/projects/json-canvas-viewer.md","filePath":"zh-Hans/projects/json-canvas-viewer.md","lastUpdated":1777202603000}'),m={name:"zh-Hans/projects/json-canvas-viewer.md"},j=l({...m,setup(u){return o({"GitHub 仓库":i,npm:n,文档:t,"JSON Canvas":s}),(g,e)=>(c(),h("div",null,[e[0]||(e[0]=a("h2",{id:"演示",tabindex:"-1"},[p("演示 "),a("a",{class:"header-anchor",href:"#演示","aria-label":"Permalink to “演示”"},"​")],-1)),v(r),e[1]||(e[1]=d('<p>上方展示的 JSON Canvas Viewer 架构插图本身就是一个 JSON Canvas Viewer 实例，其中加载了 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a>、<a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a> 与 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a> 模块。</p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p><a href="https://obsidian.md" target="_blank" rel="noreferrer">Obsidian</a> 提供了一款名为 <a href="https://jsoncanvas.org" target="_blank" rel="noreferrer">JSON Canvas</a> 的强大工具，它让我能够以非线性方式思考，非常适合复杂状态机或依赖图等场景。虽然个人使用已经足够，但由于目前缺少成熟的外部查看方式，它很难与他人分享。</p><p><code>JSON Canvas Viewer</code> 正是为了解决这个问题而生。它是一个基于 TypeScript 的 JSON Canvas 文件查看器，可让用户直接在浏览器中查看并交互画布，也能轻松嵌入到网站中。它不依赖任何特定框架构建，因此能够轻松集成到任意框架。</p><h2 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to “特性”">​</a></h2><ul><li>在浏览器中查看 JSON Canvas 文件（<code>.canvas</code>）</li><li>可轻松嵌入网站</li><li>支持交互式平移与缩放</li><li>能完整呈现 <a href="https://jsoncanvas.org/spec/1.0/" target="_blank" rel="noreferrer">官方规范</a> 定义的所有画布特性</li><li>响应式设计，适配移动端与触控板</li><li>支持懒加载</li><li>原生支持 TypeScript</li><li>具备现代美学设计，支持亮色与暗色模式</li><li>提供专为快速试用设计的 <a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#-chimpanzee-version" target="_blank" rel="noreferrer">chimp 版本</a></li><li>🔥 比在 Obsidian 中直接渲染画布更高效！</li><li>🧩 由 <a href="/zh-Hans/researches/synthkernel">SynthKernel</a> 架构驱动的开箱即用扩展性与摇树优化，当前可选模块包括： <ul><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#minimap" target="_blank" rel="noreferrer"><code>Minimap</code></a>：便于导航</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#controls" target="_blank" rel="noreferrer"><code>Controls</code></a>：显示缩放与全屏按钮</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#mistouch-preventer" target="_blank" rel="noreferrer"><code>MistouchPreventer</code></a>：防止画布拦截页面滚动</li><li><a href="https://github.com/hesprs/json-canvas-viewer/wiki/3-%F0%9F%A7%A9-Modules#debug-panel" target="_blank" rel="noreferrer"><code>DebugPanel</code></a>：显示缩放比例与位置信息</li></ul></li></ul><h2 id="集成" tabindex="-1">集成 <a class="header-anchor" href="#集成" aria-label="Permalink to “集成”">​</a></h2><p>JSON Canvas Viewer 目前可以与以下技术栈 / 技术无缝协作（包括但不限于）：</p><ul><li>✅ <strong>原生 JS/TS</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vanilla-jsts" target="_blank" rel="noreferrer">原生支持</a> - <code>json-canvas-viewer</code></li><li>✅ <strong>预渲染</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/4-%F0%9F%96%87%EF%B8%8F-Prerendering" target="_blank" rel="noreferrer"><code>renderToString</code></a> - <code>json-canvas-viewer</code></li><li>✅ <strong>Vite</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vite" target="_blank" rel="noreferrer">Vite 插件</a> - <code>vite-plugin-json-canvas</code></li><li>✅ <strong>Vue</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#vue" target="_blank" rel="noreferrer">Vue 组件</a> - <code>@json-canvas-viewer/vue</code></li><li>✅ <strong>React</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#react" target="_blank" rel="noreferrer">React 组件</a> - <code>@json-canvas-viewer/react</code></li><li>✅ <strong>Preact</strong>：<a href="https://github.com/hesprs/json-canvas-viewer/wiki/1-%F0%9F%9A%80-Quick-Start#preact" target="_blank" rel="noreferrer">Preact 组件</a> - <code>@json-canvas-viewer/preact</code></li></ul><p>了解更多关于 JSON Canvas Viewer 的信息，请访问 <a href="https://github.com/hesprs/json-canvas-viewer" target="_blank" rel="noreferrer">GitHub 仓库</a>。</p><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to “许可证”">​</a></h2><p>JSON Canvas Viewer 采用 <a href="https://mit-license.org/" target="_blank" rel="noreferrer">MIT 许可证</a> 授权。</p>',12))]))}});export{S as __pageData,j as default};
